                disabled={saving}
                className="border-0 px-8 font-medium text-[#060e20] hover:opacity-90 gradient-primary"
              >
                {saving ? (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                ) : (
                  <Save className="mr-2 h-4 w-4" />
                )}
                {isEdit ? "Update Agent" : "Create Agent"}
              </Button>
              <Button
                type="button"
                variant="secondary"
                onClick={() => router.push("/agents")}
                className="border-0 bg-surface-high text-foreground"
              >
                Cancel
              </Button>
            </div>
          </section>
        </aside>
      </form>
    </>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import {
  ShieldCheck,
  CheckCircle2,
  XCircle,
  Bot,
  Clock,
  Eye,
  AlertTriangle,
} from "lucide-react";
import { api, Task } from "@/lib/api";
import { PageHeader } from "@/components/page-header";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

export default function ApprovalsPage() {
  const [pending, setPending] = useState<Task[]>([]);
  const [history, setHistory] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTask, setSelectedTask] = useState<any>(null);
  const [processing, setProcessing] = useState<string | null>(null);
  const [tab, setTab] = useState<"pending" | "history">("pending");

  const fetchData = useCallback(async () => {
    try {
      const [pendingTasks, allTasks] = await Promise.all([
        api.tasks.list({ status: "waiting_approval" }),
        api.tasks.list({}),
      ]);
      setPending(pendingTasks);
      // History = recently completed/failed tasks that had requiresApproval
      setHistory(
        allTasks
          .filter(
            (t) =>
              t.requiresApproval &&
              (t.status === "done" || t.status === "failed") 
          )
          .slice(0, 20)
      );
    } catch {
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, [fetchData]);

  const handleApprove = async (taskId: string) => {
    setProcessing(taskId);
    try {
      await api.tasks.approve(taskId);
      fetchData();
    } catch (err) {
      console.error(err);
    }
    setProcessing(null);
  };

  const handleReject = async (taskId: string) => {
    setProcessing(taskId);
    try {
      await api.tasks.reject(taskId);
      fetchData();
    } catch (err) {
      console.error(err);
    }
    setProcessing(null);
  };

  const openPreview = async (taskId: string) => {
    try {
      const detail = await api.tasks.get(taskId);
      setSelectedTask(detail);
