              </div>
              <div>
                <h4 className="text-xs text-on-surface-dim uppercase tracking-wider font-bold mb-1">Input</h4>
                <div className="text-sm p-3 rounded-lg" style={{ background: "var(--surface-container)" }}>
                  {selectedTask.input}
