  usage?: { prompt_tokens: number; completion_tokens: number; total_tokens: number };
}

export default function PlaygroundPage() {
  const [agents, setAgents] = useState<Agent[]>([]);
  const [selectedAgentId, setSelectedAgentId] = useState("");
  const [messages, setMessages] = useState<ChatMsg[]>([]);
  const [input, setInput] = useState("");
  const [sending, setSending] = useState(false);
  const [totalTokens, setTotalTokens] = useState(0);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    api.agents.list().then((a) => {
      setAgents(a);
      if (a.length > 0) setSelectedAgentId(a[0].id);
    });
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const selectedAgent = agents.find((a) => a.id === selectedAgentId);

  const handleSend = useCallback(async () => {
    if (!input.trim() || !selectedAgentId || sending) return;

    const userMsg: ChatMsg = { role: "user", content: input.trim() };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput("");
    setSending(true);

    try {
      const apiMessages = newMessages.map((m) => ({
        role: m.role,
        content: m.content,
      }));
      const res: PlaygroundResponse = await api.playground.chat(
        selectedAgentId,
        apiMessages
      );

      const assistantMsg: ChatMsg = {
        role: "assistant",
        content: res.content,
        toolCalls: res.toolCalls,
        usage: res.usage,
      };
      setMessages([...newMessages, assistantMsg]);
      setTotalTokens((prev) => prev + (res.usage?.total_tokens || 0));
    } catch (err: any) {
      setMessages([
        ...newMessages,
        {
          role: "assistant",
          content: `⚠️ Error: ${err?.message || "Failed to get response"}`,
        },
      ]);
    }
    setSending(false);
  }, [input, selectedAgentId, sending, messages]);

  const handleClear = () => {
    setMessages([]);
    setTotalTokens(0);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-2rem)]">
      {/* Header */}
      <div className="shrink-0 mb-4">
        <PageHeader
          title="Agent Playground"
          description="Test-drive your agents with an interactive chat interface"
        />
      </div>

      {/* Agent Selector Bar */}
      <div
        className="shrink-0 flex items-center gap-4 p-4 rounded-xl mb-4"
        style={{
          background: "var(--surface-container)",
          border: "1px solid rgba(255,255,255,0.05)",
        }}
      >
        <Bot className="w-5 h-5 text-accent-cyan shrink-0" />
        <Select
          value={selectedAgentId}
          onValueChange={(val) => {
            setSelectedAgentId(val || "");
            handleClear();
          }}
        >
          <SelectTrigger className="bg-surface-high border-0 text-foreground max-w-md">
            <SelectValue placeholder="Select an agent..." />
          </SelectTrigger>
          <SelectContent
            style={{
              background: "var(--surface-high)",
              borderColor: "rgba(255,255,255,0.1)",
            }}
          >
            {agents.map((a) => (
              <SelectItem key={a.id} value={a.id} className="text-foreground">
                <span className="flex items-center gap-2">
                  <Bot className="w-3 h-3 text-accent-cyan" /> {a.name}
                  <span className="text-[10px] text-on-surface-dim ml-1">
                    — {a.role}
                  </span>
                </span>
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        {selectedAgent && (
          <div className="flex items-center gap-4 ml-auto text-xs">
            <div className="flex items-center gap-1.5">
              <Wrench className="w-3 h-3" style={{ color: "var(--on-surface-dim)" }} />
              <span style={{ color: "var(--on-surface-dim)" }}>
                {selectedAgent.allowedTools.length} tools
              </span>
            </div>
            <div className="flex items-center gap-1.5">
              <Zap className="w-3 h-3" style={{ color: "var(--on-surface-dim)" }} />
              <span style={{ color: "var(--on-surface-dim)" }}>
                {totalTokens} tokens used
              </span>
            </div>
            <Button
              variant="ghost"
              size="sm"
              onClick={handleClear}
              className="text-on-surface-dim hover:text-foreground"
            >
              <RotateCcw className="w-3.5 h-3.5 mr-1" /> Reset
            </Button>
          </div>
        )}
      </div>

      {/* Chat Area */}
      <div
        className="flex-1 overflow-y-auto rounded-xl p-6 mb-4"
        style={{
          background: "var(--surface-base)",
          border: "1px solid rgba(255,255,255,0.05)",
        }}
      >
        {messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center">
            <div
              className="w-16 h-16 rounded-2xl flex items-center justify-center mb-4"
              style={{
                background: "rgba(123, 208, 255, 0.08)",
                border: "1px solid rgba(123, 208, 255, 0.15)",
              }}
            >
              <Sparkles className="w-8 h-8 text-accent-cyan" />
            </div>
            <h3 className="font-heading text-lg font-semibold mb-2">
              Start a conversation
            </h3>
            <p
              className="text-sm max-w-md"
              style={{ color: "var(--on-surface-dim)" }}
            >
              Select an agent above and send a message to test its personality,
              tools, and system prompt in real-time.
            </p>
          </div>
        ) : (
          <div className="space-y-5">
            {messages.map((msg, i) => (
              <div
                key={i}
                className={`flex gap-3 animate-slide-in ${
                  msg.role === "user" ? "justify-end" : "justify-start"
                }`}
                style={{ animationDelay: `${i * 30}ms` }}
              >
                {msg.role === "assistant" && (
                  <div
                    className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0 mt-1"
                    style={{
                      background: "rgba(123, 208, 255, 0.1)",
                      border: "1px solid rgba(123, 208, 255, 0.2)",
                    }}
                  >
                    <Bot className="w-4 h-4 text-accent-cyan" />
                  </div>
                )}

                <div
                  className={`max-w-[75%] rounded-xl px-4 py-3 text-sm leading-relaxed ${
                    msg.role === "user" ? "rounded-br-sm" : "rounded-bl-sm"
                  }`}
                  style={{
                    background:
                      msg.role === "user"
                        ? "linear-gradient(135deg, rgba(123, 208, 255, 0.15), rgba(0, 138, 187, 0.1))"
                        : "var(--surface-container)",
                    border: `1px solid ${
                      msg.role === "user"
                        ? "rgba(123, 208, 255, 0.2)"
                        : "rgba(255,255,255,0.05)"
                    }`,
                  }}
                >
                  <div className="whitespace-pre-wrap">{msg.content}</div>

                  {/* Tool calls */}
                  {msg.toolCalls && msg.toolCalls.length > 0 && (
                    <div className="mt-3 space-y-2">
                      {msg.toolCalls.map((tc, j) => (
                        <div
                          key={j}
                          className="rounded-lg p-2.5 text-[11px]"
                          style={{
                            background: "rgba(123, 208, 255, 0.05)",
                            border: "1px solid rgba(123, 208, 255, 0.1)",
                          }}
                        >
                          <div className="flex items-center gap-1.5 mb-1 text-accent-cyan font-semibold">
                            <Wrench className="w-3 h-3" /> {tc.name}
                          </div>
                          <pre
                            className="text-[10px] overflow-x-auto font-mono"
                            style={{ color: "var(--on-surface-dim)" }}
                          >
                            {(() => {
                              try {
                                return JSON.stringify(
                                  JSON.parse(tc.arguments),
                                  null,
                                  2
                                );
                              } catch {
                                return tc.arguments;
                              }
                            })()}
                          </pre>
                        </div>
                      ))}
                    </div>
                  )}

                  {/* Token usage */}
                  {msg.usage && (
                    <div
                      className="mt-2 text-[10px] flex items-center gap-2"
                      style={{ color: "var(--on-surface-dim)" }}
                    >
                      <Zap className="w-2.5 h-2.5" />
                      {msg.usage.total_tokens} tokens ({msg.usage.prompt_tokens}{" "}
                      prompt + {msg.usage.completion_tokens} completion)
                    </div>
                  )}
                </div>

                {msg.role === "user" && (
                  <div
                    className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0 mt-1"
                    style={{
                      background: "var(--surface-high)",
                      border: "1px solid rgba(255,255,255,0.08)",
                    }}
                  >
                    <User className="w-4 h-4 text-foreground" />
                  </div>
                )}
              </div>
            ))}

            {sending && (
              <div className="flex gap-3 animate-slide-in">
                <div
                  className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0"
                  style={{
                    background: "rgba(123, 208, 255, 0.1)",
                    border: "1px solid rgba(123, 208, 255, 0.2)",
                  }}
                >
                  <Bot className="w-4 h-4 text-accent-cyan animate-pulse" />
                </div>
                <div
                  className="rounded-xl rounded-bl-sm px-4 py-3"
                  style={{
                    background: "var(--surface-container)",
                    border: "1px solid rgba(255,255,255,0.05)",
                  }}
                >
                  <div className="flex gap-1.5">
                    <div
                      className="w-2 h-2 rounded-full animate-bounce bg-accent-cyan"
                      style={{ animationDelay: "0ms" }}
                    />
                    <div
                      className="w-2 h-2 rounded-full animate-bounce bg-accent-cyan"
                      style={{ animationDelay: "150ms" }}
                    />
                    <div
                      className="w-2 h-2 rounded-full animate-bounce bg-accent-cyan"
                      style={{ animationDelay: "300ms" }}
                    />
                  </div>
                </div>
              </div>
            )}
            <div ref={bottomRef} />
          </div>
        )}
      </div>

      {/* Input Area */}
      <div
        className="shrink-0 rounded-xl p-4"
        style={{
          background: "var(--surface-container)",
          border: "1px solid rgba(255,255,255,0.05)",
        }}
      >
        <div className="flex gap-3">
          <Textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={
              selectedAgent
                ? `Message ${selectedAgent.name}...`
                : "Select an agent to start chatting..."
            }
            disabled={!selectedAgentId || sending}
            rows={2}
            className="bg-surface-high border-0 text-foreground resize-none flex-1 placeholder:text-on-surface-dim"
          />
          <Button
            onClick={handleSend}
            disabled={!input.trim() || !selectedAgentId || sending}
            className="gradient-primary text-[#060e20] font-semibold self-end h-10 w-10 p-0"
          >
            <Send className="w-4 h-4" />
          </Button>
        </div>
        <p className="text-[10px] mt-2" style={{ color: "var(--on-surface-dim)" }}>
          Press Enter to send, Shift+Enter for new line. Messages are not
          persisted.
        </p>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, useRef } from "react";
import {
  User,
  Mail,
  Save,
  Loader2,
  Shield,
  Key,
  CheckCircle,
  Calendar,
  AlertTriangle,
  Eye,
  EyeOff,
  Camera,
  Trash2,
} from "lucide-react";
import { api } from "@/lib/api";
import type { UserProfile } from "@/lib/api";
import { PageHeader } from "@/components/page-header";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

export default function ProfilePage() {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);

  // Profile form
  const [fullName, setFullName] = useState("");
  const [email, setEmail] = useState("");
  const [savingProfile, setSavingProfile] = useState(false);
  const [profileMsg, setProfileMsg] = useState<{
    type: "success" | "error";
    text: string;
  } | null>(null);

  // Password form
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [savingPassword, setSavingPassword] = useState(false);
  const [passwordMsg, setPasswordMsg] = useState<{
    type: "success" | "error";
    text: string;
  } | null>(null);

  // Password visibility
  const [showCurrentPassword, setShowCurrentPassword] = useState(false);
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  // Avatar upload
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploadingAvatar, setUploadingAvatar] = useState(false);
  const [deletingAvatar, setDeletingAvatar] = useState(false);
  const [optimisticAvatar, setOptimisticAvatar] = useState<string | null>(null);

  useEffect(() => {
    api.auth
      .me()
      .then((u) => {
        setUser(u);
        setFullName(u.full_name || "");
        setEmail(u.email);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const handleSaveProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingProfile(true);
    setProfileMsg(null);

    try {
      const updated = await api.auth.updateProfile({
        full_name: fullName,
        email,
      });
      setUser(updated);
      setProfileMsg({ type: "success", text: "Profile updated successfully" });
    } catch (err: any) {
      setProfileMsg({
        type: "error",
        text: err.message || "Failed to update profile",
      });
    } finally {
      setSavingProfile(false);
    }
  };

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setPasswordMsg(null);

    if (newPassword !== confirmPassword) {
      setPasswordMsg({ type: "error", text: "New passwords do not match" });
      return;
    }
    if (newPassword.length < 6) {
      setPasswordMsg({
        type: "error",
        text: "Password must be at least 6 characters",
      });
      return;
    }

    setSavingPassword(true);
    try {
      await api.auth.changePassword({
        current_password: currentPassword,
        new_password: newPassword,
      });
      setPasswordMsg({
        type: "success",
        text: "Password changed successfully",
      });
      setCurrentPassword("");
      setNewPassword("");
      setConfirmPassword("");
    } catch (err: any) {
      setPasswordMsg({
        type: "error",
        text: err.message || "Failed to change password",
      });
    } finally {
      setSavingPassword(false);
    }
  };

  if (loading) {
    return (
      <div
        className="flex items-center justify-center py-20 text-sm"
        style={{ color: "var(--on-surface-dim)" }}
      >
        <Loader2 className="w-5 h-5 animate-spin mr-2" />
        Loading profile...
      </div>
    );
  }

  if (!user) {
    return (
      <div className="text-center py-20">
        <p className="text-lg font-heading font-medium mb-4">
          Could not load profile
        </p>
      </div>
    );
  }

  const initials = (user.full_name || user.email)
    .split(" ")
    .map((w) => w[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);

  const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const objectUrl = URL.createObjectURL(file);
    setOptimisticAvatar(objectUrl);
    setUploadingAvatar(true);
    setProfileMsg(null);
    try {
      const updated = await api.auth.uploadAvatar(file);
      setUser(updated);
      setProfileMsg({ type: "success", text: "Avatar updated successfully" });
    } catch (err: any) {
      setProfileMsg({ type: "error", text: err.message || "Failed to upload avatar" });
      setOptimisticAvatar(null); // Revert on failure
    } finally {
      setUploadingAvatar(false);
      URL.revokeObjectURL(objectUrl);
      setOptimisticAvatar(null);
      if (fileInputRef.current) fileInputRef.current.value = "";
    }
  };

  const handleDeleteAvatar = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!user?.avatar_url) return;

    setDeletingAvatar(true);
    setProfileMsg(null);
    try {
      const updated = await api.auth.deleteAvatar();
      setUser(updated);
      setProfileMsg({ type: "success", text: "Avatar removed successfully" });
    } catch (err: any) {
      setProfileMsg({ type: "error", text: err.message || "Failed to remove avatar" });
    } finally {
      setDeletingAvatar(false);
    }
  };

  return (
    <>
      <PageHeader
        title="Profile"
        description="Manage your account settings and security"
      />

      <div className="max-w-5xl space-y-6 md:space-y-0 md:grid md:grid-cols-12 md:gap-6 w-full mb-10">
        {/* Left Column */}
        <div className="md:col-span-4 lg:col-span-4 space-y-6">
          {/* User Card */}
          <div
            className="relative rounded-2xl p-6 overflow-hidden flex flex-col items-center text-center shadow-sm"
            style={{ background: "var(--surface-container)" }}
          >
            <div className="absolute top-0 left-0 right-0 h-32 bg-gradient-to-br from-[#7bd0ff]/20 via-[#008abb]/10 to-transparent" />

            <div className="relative mt-2 mb-4 group shrink-0">
              {(optimisticAvatar || user.avatar_url) ? (
                <>
                  <img
                    src={optimisticAvatar || user.avatar_url!}
                    alt="Avatar"
                    className={`w-28 h-28 rounded-2xl object-cover shadow-xl border-4 border-[var(--surface-container)] ${(uploadingAvatar || deletingAvatar) ? "opacity-50" : ""}`}
                  />
                  {!uploadingAvatar && !deletingAvatar && (
                    <button
                      type="button"
                      onClick={handleDeleteAvatar}
                      className="absolute -top-2 -right-2 bg-[#ffb4ab] hover:bg-[#ff897d] text-[#93000a] rounded-full p-1.5 opacity-0 group-hover:opacity-100 transition-all z-10 shadow-sm"
                      title="Remove avatar"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </>
              ) : (
                <div className={`w-28 h-28 rounded-2xl gradient-primary flex items-center justify-center text-3xl font-heading font-bold text-[#060e20] shadow-xl border-4 border-[var(--surface-container)] ${(uploadingAvatar || deletingAvatar) ? "opacity-50" : ""}`}>
                  {initials}
                </div>
              )}
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={uploadingAvatar || deletingAvatar}
                className="absolute inset-0 rounded-2xl flex items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer"
              >
                {(uploadingAvatar || deletingAvatar) ? (
                  <Loader2 className="w-6 h-6 text-white animate-spin" />
                ) : (
                  <Camera className="w-6 h-6 text-white" />
                )}
              </button>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/jpeg,image/png,image/webp,image/gif"
                className="hidden"
                onChange={handleAvatarUpload}
              />
            </div>

            <div className="relative w-full z-10">
              <h2 className="text-xl font-heading font-semibold text-foreground truncate">
                {user.full_name || "No name set"}
              </h2>
              <p
                className="text-sm mt-1 flex items-center justify-center gap-1.5"
                style={{ color: "var(--on-surface-dim)" }}
              >
                <Mail className="w-3.5 h-3.5" />
                {user.email}
              </p>

              <div className="flex flex-col items-center gap-2 mt-5 w-full">
                <span
                  className="text-xs flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-full font-medium w-full"
                  style={{
                    background: user.is_active
                      ? "rgba(78, 222, 163, 0.15)"
                      : "rgba(255, 180, 171, 0.15)",
                    color: user.is_active ? "#4edea3" : "#ffb4ab",
                  }}
                >
                  <Shield className="w-4 h-4" />
                  {user.is_active ? "Active Account" : "Inactive Account"}
                </span>
                <span
                  className="text-xs flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-full font-medium w-full"
                  style={{ background: "var(--surface-lowest)", color: "var(--on-surface-dim)" }}
                >
                  <Calendar className="w-4 h-4" />
                  Joined {new Date(user.created_at).toLocaleDateString()}
                </span>
              </div>
            </div>
          </div>

          {/* Account Details moved to right under User Card */}
          <div
            className="rounded-2xl p-6 shadow-sm"
            style={{ background: "var(--surface-container)" }}
          >
            <h3 className="text-sm font-heading font-semibold text-foreground mb-4 flex items-center gap-2">
              <Shield className="w-4 h-4 text-accent-cyan" />
              Account Details
            </h3>
            <div className="grid grid-cols-1 gap-3">
              <InfoCard label="User ID" value={user.id} mono />
              <InfoCard
                label="Status"
                value={user.is_active ? "Active" : "Inactive"}
                color={user.is_active ? "#4edea3" : "#ffb4ab"}
              />
              <InfoCard
                label="Member Since"
                value={new Date(user.created_at).toLocaleDateString("en-US", {
                  year: "numeric",
                  month: "long",
                  day: "numeric",
                })}
              />
            </div>
          </div>
        </div>

        {/* Right Column - Forms */}
        <div className="md:col-span-8 lg:col-span-8 space-y-6">

        {/* Profile Settings */}
        <div
          className="rounded-2xl p-6"
          style={{ background: "var(--surface-container)" }}
        >
          <h3 className="text-sm font-heading font-semibold text-foreground mb-5 flex items-center gap-2">
            <User className="w-4 h-4 text-accent-cyan" />
            Profile Information
          </h3>

          {profileMsg && (
            <div
              className={`mb-5 p-3 rounded-lg text-sm flex items-center gap-2 ${
                profileMsg.type === "success"
                  ? "text-[#4edea3]"
                  : "text-[#ffb4ab]"
              }`}
              style={{
                background:
                  profileMsg.type === "success"
                    ? "rgba(78, 222, 163, 0.1)"
                    : "rgba(255, 180, 171, 0.1)",
              }}
            >
              {profileMsg.type === "success" ? (
                <CheckCircle className="w-4 h-4 shrink-0" />
              ) : (
                <AlertTriangle className="w-4 h-4 shrink-0" />
              )}
              {profileMsg.text}
            </div>
          )}

          <form onSubmit={handleSaveProfile} className="space-y-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label
                  htmlFor="fullName"
                  className="text-[11px] uppercase tracking-[0.05rem]"
                  style={{ color: "var(--on-surface-dim)" }}
                >
                  Full Name
                </Label>
                <Input
                  id="fullName"
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                  placeholder="Your name"
                  className="bg-surface-lowest border-0 text-foreground h-11"
                />
              </div>
              <div className="space-y-2">
                <Label
                  htmlFor="profileEmail"
                  className="text-[11px] uppercase tracking-[0.05rem]"
                  style={{ color: "var(--on-surface-dim)" }}
                >
                  Email Address
                </Label>
                <Input
                  id="profileEmail"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="you@example.com"
                  required
