                    <button
                      onClick={() => handleDelete(s.id)}
                      className="p-2 rounded-lg hover:bg-[#ffb4ab]/10 transition-colors opacity-0 group-hover:opacity-100"
                      title="Delete Schedule"
                    >
                      <Trash2 className="w-4 h-4 text-[#ffb4ab]" />
                    </button>
                  </div>
                </div>

                {/* Prompt preview */}
                <div className="mt-3 ml-14 text-xs line-clamp-1" style={{ color: "var(--on-surface-dim)" }}>
                  <span className="text-white/30 mr-1.5">Prompt:</span> {s.promptPayload}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Create / Edit Dialog */}
      <Dialog open={showCreate} onOpenChange={(open) => { if (!open) { setShowCreate(false); resetForm(); } }}>
        <DialogContent className="sm:max-w-xl" style={{ background: "var(--surface-high)", borderColor: "rgba(255,255,255,0.1)", borderWidth: "1px" }}>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 font-heading">
              <Clock className="w-5 h-5 text-accent-cyan" />
              {editSchedule ? "Edit Schedule" : "New Schedule"}
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-5 py-2 max-h-[60vh] overflow-y-auto px-2 -mx-2">
            {/* Name */}
            <div>
              <Label className="text-sm font-medium text-foreground mb-1.5 block">Schedule Name</Label>
              <Input
                value={formName}
                onChange={(e) => setFormName(e.target.value)}
                placeholder="e.g. Daily Market Report"
                className="bg-surface-container border-0 text-foreground"
              />
            </div>

            {/* Agent */}
            <div>
              <Label className="text-sm font-medium text-foreground mb-1.5 block">Assign to Agent</Label>
              <Select value={formAgentId} onValueChange={(val) => setFormAgentId(val || "")}>
                <SelectTrigger className="bg-surface-container border-0 text-foreground">
                  <SelectValue placeholder="Select an agent..." />
                </SelectTrigger>
                <SelectContent style={{ background: "var(--surface-high)", borderColor: "rgba(255,255,255,0.1)" }}>
                  {agents.map(a => (
                    <SelectItem key={a.id} value={a.id} className="text-foreground">
                      <span className="flex items-center gap-2">
                        <Bot className="w-3 h-3 text-accent-cyan" /> {a.name}
                      </span>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Prompt */}
            <div>
              <Label className="text-sm font-medium text-foreground mb-1.5 block">Prompt / Instruction</Label>
              <Textarea
                value={formPrompt}
                onChange={(e) => setFormPrompt(e.target.value)}
                placeholder="What should the agent do when triggered?"
                rows={3}
                className="bg-surface-container border-0 text-foreground resize-none"
              />
            </div>

            {/* Schedule Type */}
            <div>
              <Label className="text-sm font-medium text-foreground mb-2 block">Trigger Type</Label>
              <div className="grid grid-cols-3 gap-2">
                {SCHEDULE_TYPE_OPTIONS.map(opt => {
                  const Icon = opt.icon;
                  const selected = formType === opt.value;
                  return (
                    <button
                      key={opt.value}
                      onClick={() => setFormType(opt.value as any)}
                      className="p-3 rounded-lg text-center transition-all duration-200 border"
                      style={{
                        background: selected ? "rgba(123,208,255,0.1)" : "var(--surface-container)",
                        borderColor: selected ? "rgba(123,208,255,0.3)" : "transparent",
                      }}
                    >
                      <Icon className="w-5 h-5 mx-auto mb-1" style={{ color: selected ? "#7bd0ff" : "var(--on-surface-dim)" }} />
                      <span className="text-[11px] font-semibold" style={{ color: selected ? "#7bd0ff" : "var(--on-surface-dim)" }}>{opt.label}</span>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Cron Config */}
            {formType === "cron" && (
              <div>
                <Label className="text-sm font-medium text-foreground mb-1.5 block">Cron Expression</Label>
                <Input
                  value={formCron}
                  onChange={e => setFormCron(e.target.value)}
                  placeholder="0 8 * * *"
                  className="bg-surface-container border-0 text-foreground font-mono mb-2"
                />
                <div className="flex flex-wrap gap-1.5">
                  {CRON_PRESETS.map(p => (
                    <button
                      key={p.value}
                      onClick={() => setFormCron(p.value)}
                      className="text-[10px] px-2 py-1 rounded-md transition-colors font-medium"
                      style={{
                        background: formCron === p.value ? "rgba(123,208,255,0.15)" : "var(--surface-container)",
                        color: formCron === p.value ? "#7bd0ff" : "var(--on-surface-dim)",
                      }}
                    >
                      {p.label}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Interval Config */}
            {formType === "interval" && (
              <div>
                <Label className="text-sm font-medium text-foreground mb-1.5 block">Interval (seconds)</Label>
                <Input
                  type="number"
                  value={formInterval}
                  onChange={e => setFormInterval(Number(e.target.value))}
                  min={60}
                  className="bg-surface-container border-0 text-foreground"
                />
                <p className="text-[11px] mt-1" style={{ color: "var(--on-surface-dim)" }}>
                  Minimum 60 seconds. {formInterval >= 3600 ? `≈ ${(formInterval / 3600).toFixed(1)} hours` : formInterval >= 60 ? `≈ ${(formInterval / 60).toFixed(0)} minutes` : ""}
                </p>
              </div>
            )}

            {/* Once Config */}
            {formType === "once" && (
              <div>
                <Label className="text-sm font-medium text-foreground mb-1.5 block">Run At (datetime)</Label>
                <Input
                  type="datetime-local"
                  value={formRunAt}
                  onChange={e => setFormRunAt(e.target.value)}
                  className="bg-surface-container border-0 text-foreground"
                />
              </div>
            )}

            {/* Timezone */}
            <div>
              <Label className="text-sm font-medium text-foreground mb-1.5 block">Timezone</Label>
              <Select value={formTimezone} onValueChange={(val) => setFormTimezone(val || "")}>
                <SelectTrigger className="bg-surface-container border-0 text-foreground">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent style={{ background: "var(--surface-high)", borderColor: "rgba(255,255,255,0.1)" }}>
                  {["Asia/Ho_Chi_Minh", "UTC", "US/Eastern", "US/Pacific", "Europe/London", "Asia/Tokyo", "Asia/Singapore"].map(tz => (
                    <SelectItem key={tz} value={tz} className="text-foreground">{tz}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Active toggle */}
            <div className="flex items-center justify-between">
              <Label className="text-sm font-medium text-foreground">Enable immediately</Label>
              <Switch checked={formActive} onCheckedChange={setFormActive} />
            </div>
          </div>

          {/* Actions */}
          <div className="flex justify-end gap-2 pt-4 border-t border-white/[0.05]">
            <Button
              variant="ghost"
              onClick={() => { setShowCreate(false); resetForm(); }}
              className="text-on-surface-dim hover:text-foreground"
            >
              Cancel
            </Button>
            <Button
              onClick={handleSave}
              disabled={saving || !formName || !formAgentId || !formPrompt}
              className="gradient-primary text-[#060e20] font-semibold"
            >
              {saving ? "Saving..." : editSchedule ? "Update Schedule" : "Create Schedule"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import {
  ArrowLeft,
  Bot,
  Play,
  XCircle,
  RefreshCw,
  Loader2,
  GitBranch,
  Brain,
  Zap,
  AlertTriangle,
  CheckCircle,
  Clock,
  ArrowRight,
} from "lucide-react";
import { api, getExecutionWebSocketUrl } from "@/lib/api";
import type { TaskDetail, ExecutionStep } from "@/lib/api";
import { PageHeader } from "@/components/page-header";
import { StatusBadge } from "@/components/status-badge";
import { Button } from "@/components/ui/button";
import ExecutionTimeline from "@/components/execution-timeline";

const stepIcons: Record<string, typeof Brain> = {
  thinking: Brain,
  action: Zap,
  delegation: GitBranch,
  result: CheckCircle,
  error: AlertTriangle,
  waiting: Clock,
};

const stepColors: Record<string, string> = {
  thinking: "#7bd0ff",
  action: "#008abb",
  delegation: "#4edea3",
  result: "#4edea3",
  error: "#ffb4ab",
  waiting: "#f0c674",
};

export default function TaskDetailPage() {
  const params = useParams();
  const router = useRouter();
  const taskId = params.id as string;
  const [task, setTask] = useState<TaskDetail | null>(null);
  const [steps, setSteps] = useState<ExecutionStep[]>([]);
  const [loading, setLoading] = useState(true);
  const [executing, setExecuting] = useState(false);
  const stepsEndRef = useRef<HTMLDivElement>(null);
  const wsRef = useRef<WebSocket | null>(null);

  const loadData = async () => {
    try {
      const t = await api.tasks.get(taskId);
      setTask(t);

      if (t.execution) {
        const s = await api.executions.getSteps(t.execution.id);
        setSteps(s);
      }
    } catch {
      // Ignore errors
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
    // Poll while running
    const interval = setInterval(() => {
      loadData();
    }, 3000);
    return () => clearInterval(interval);
  }, [taskId]);

  // WebSocket for realtime updates
  useEffect(() => {
    if (!task?.execution?.id) return;

    const wsUrl = getExecutionWebSocketUrl(task.execution.id);
    try {
      const ws = new WebSocket(wsUrl);
      wsRef.current = ws;

      ws.onmessage = (event) => {
        const data = JSON.parse(event.data);
        if (data.type === "step") {
          setSteps((prev) => [
            ...prev,
            {
              id: Date.now().toString(),
              executionId: task.execution!.id,
              taskId: taskId,
              agentId: "",
              stepType: data.stepType,
              content: data.content,
              meta: data.meta || {},
              createdAt: new Date().toISOString(),
            },
          ]);
        }
        if (
          data.type === "execution_completed" ||
          data.type === "execution_failed"
        ) {
          loadData();
        }
      };

      return () => {
        ws.close();
      };
    } catch {
      // WS not available
    }
  }, [task?.execution?.id]);

  useEffect(() => {
    stepsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [steps]);

  const handleExecute = async () => {
    setExecuting(true);
    try {
      await api.tasks.execute(taskId);
      await loadData();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setExecuting(false);
    }
  };

  const handleCancel = async () => {
    try {
      await api.tasks.cancel(taskId);
      await loadData();
    } catch (err: any) {
      alert(err.message);
    }
  };

  if (loading) {
    return (
      <div
        className="flex items-center justify-center py-20 text-sm"
        style={{ color: "var(--on-surface-dim)" }}
      >
        <Loader2 className="w-5 h-5 animate-spin mr-2" />
        Loading task...
      </div>
    );
  }

  if (!task) {
    return (
      <div className="text-center py-20">
        <p className="text-lg font-heading font-medium mb-4">Task not found</p>
        <Link href="/tasks">
          <Button
            variant="secondary"
            className="bg-surface-high text-foreground border-0"
          >
            Back to Tasks
          </Button>
        </Link>
      </div>
    );
  }

  const isRunning = task.status === "running";
  const canExecute =
    task.status === "queued" || task.status === "failed";
  const canCancel =
    task.status === "running" ||
    task.status === "queued" ||
    task.status === "waiting_approval";

  return (
    <>
      {/* Back button */}
      <button
        onClick={() => router.push("/tasks")}
        className="flex items-center gap-2 text-sm mb-6 transition-colors hover:text-accent-cyan"
        style={{ color: "var(--on-surface-dim)" }}
      >
        <ArrowLeft className="w-4 h-4" />
        Back to Tasks
      </button>

      <PageHeader
        title={task.title}
        description={`Assigned to ${task.agentName || task.assignedAgentId}`}
        actions={
          <div className="flex items-center gap-3">
            <StatusBadge status={task.status} />
            {canExecute && (
              <Button
                onClick={handleExecute}
                disabled={executing}
                className="gradient-primary text-[#060e20] font-medium border-0 hover:opacity-90"
              >
                {executing ? (
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                ) : (
                  <Play className="w-4 h-4 mr-2" />
                )}
                {task.status === "failed" ? "Retry" : "Execute"}
              </Button>
            )}
            {canCancel && (
              <Button
                onClick={handleCancel}
                variant="secondary"
                className="bg-surface-high text-foreground border-0 hover:bg-surface-highest"
              >
                <XCircle className="w-4 h-4 mr-2" />
                Cancel
              </Button>
            )}
            <Button
              onClick={loadData}
              variant="secondary"
              className="bg-surface-high text-foreground border-0 hover:bg-surface-highest"
              size="icon"
            >
              <RefreshCw className="w-4 h-4" />
            </Button>
          </div>
        }
      />

      <div className="grid grid-cols-1 lg:grid-cols-[1fr_340px] gap-6">
        {/* Main: Execution Timeline */}
        <div>
          {/* Task Input */}
          <div
            className="rounded-xl p-5 mb-6"
            style={{ background: "var(--surface-container)" }}
          >
            <h3
              className="text-[11px] font-medium uppercase tracking-[0.05rem] mb-3"
              style={{ color: "var(--on-surface-dim)" }}
            >
              Task Input
            </h3>
            <div
              className="rounded-lg p-4 text-sm font-mono whitespace-pre-wrap"
              style={{ background: "var(--surface-lowest)" }}
            >
              {task.input}
            </div>
          </div>

          {/* Execution Steps */}
          <div
            className="rounded-xl p-5"
            style={{ background: "var(--surface-container)" }}
          >
            <h3
              className="text-[11px] font-medium uppercase tracking-[0.05rem] mb-5"
              style={{ color: "var(--on-surface-dim)" }}
            >
              Execution Timeline
            </h3>
            <ExecutionTimeline steps={steps} isRunning={isRunning} />
          </div>

          {/* Result */}
          {task.result && (
            <div
              className="rounded-xl p-5 mt-6"
              style={{ background: "var(--surface-container)" }}
            >
              <h3
                className="text-[11px] font-medium uppercase tracking-[0.05rem] mb-3"
                style={{ color: "var(--accent-teal)" }}
              >
                Final Result
              </h3>
              <div
                className="rounded-lg p-4 text-sm whitespace-pre-wrap"
                style={{ background: "var(--surface-lowest)" }}
              >
                {task.result}
              </div>
            </div>
          )}

          {/* Error */}
          {task.error && (
            <div
              className="rounded-xl p-5 mt-6 relative"
              style={{
                background: "var(--surface-container)",
                borderTop: "4px solid #93000a",
              }}
            >
              <h3
                className="text-[11px] font-medium uppercase tracking-[0.05rem] mb-3 flex items-center gap-2"
                style={{ color: "#ffb4ab" }}
              >
                <AlertTriangle className="w-3.5 h-3.5" />
                Error
              </h3>
              <div
                className="rounded-lg p-4 text-sm whitespace-pre-wrap"
                style={{ background: "var(--surface-lowest)" }}
              >
                {task.error}
              </div>
            </div>
          )}
        </div>

        {/* Sidebar: Task Info + Delegation Chain */}
        <div className="space-y-6">
          {/* Task Info */}
          <div
            className="rounded-xl p-5"
            style={{ background: "var(--surface-container)" }}
          >
            <h3
              className="text-[11px] font-medium uppercase tracking-[0.05rem] mb-4"
              style={{ color: "var(--on-surface-dim)" }}
            >
              Task Info
            </h3>
            <div className="space-y-3">
              <InfoRow
                label="Status"
                value={<StatusBadge status={task.status} />}
              />
              <InfoRow
                label="Agent"
                value={
                  <span className="text-sm">
                    {task.agentName || task.assignedAgentId}
                  </span>
                }
              />
              <InfoRow
                label="Created"
                value={
                  <span className="text-sm">
                    {new Date(task.createdAt).toLocaleString()}
                  </span>
                }
              />
              <InfoRow
                label="Created By"
                value={<span className="text-sm">{task.createdBy}</span>}
              />
              <InfoRow
                label="Delegation"
                value={
                  <span className="text-sm">
                    {task.allowDelegation ? "Allowed" : "Disabled"}
                  </span>
                }
              />
              <InfoRow
                label="Approval"
                value={
                  <span className="text-sm">
                    {task.requiresApproval ? "Required" : "Not required"}
                  </span>
                }
              />
            </div>
          </div>

          {/* Execution Info */}
          {task.execution && (
            <div
              className="rounded-xl p-5"
              style={{ background: "var(--surface-container)" }}
            >
              <h3
                className="text-[11px] font-medium uppercase tracking-[0.05rem] mb-4"
                style={{ color: "var(--on-surface-dim)" }}
              >
                Execution
              </h3>
              <div className="space-y-3">
                <InfoRow
                  label="Status"
                  value={
                    <span className="text-sm">{task.execution.status}</span>
                  }
                />
                <InfoRow
                  label="Started"
                  value={
                    <span className="text-sm">
                      {new Date(task.execution.startedAt).toLocaleTimeString()}
                    </span>
                  }
                />
                {task.execution.endedAt && (
                  <InfoRow
                    label="Ended"
                    value={
                      <span className="text-sm">
                        {new Date(
                          task.execution.endedAt
                        ).toLocaleTimeString()}
                      </span>
                    }
                  />
                )}
                <InfoRow
                  label="Steps"
                  value={
                    <span className="text-sm font-heading font-semibold text-accent-cyan">
                      {steps.length}
                    </span>
                  }
                />
              </div>
            </div>
          )}

          {/* Delegation Chain (Subtasks) */}
          {task.subtasks.length > 0 && (
            <div
              className="rounded-xl p-5"
              style={{ background: "var(--surface-container)" }}
            >
              <h3
                className="text-[11px] font-medium uppercase tracking-[0.05rem] mb-4 flex items-center gap-2"
                style={{ color: "var(--on-surface-dim)" }}
              >
                <GitBranch className="w-3.5 h-3.5" />
                Delegation Chain
              </h3>
              <div className="space-y-2">
                {task.subtasks.map((sub) => (
                  <Link
                    href={`/tasks/${sub.id}`}
                    key={sub.id}
                    className="flex items-center gap-3 p-3 rounded-lg transition-colors hover:bg-surface-high"
                  >
                    <Bot
                      className="w-4 h-4 shrink-0"
                      style={{ color: "var(--accent-teal)" }}
                    />
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium truncate">
                        {sub.title}
                      </p>
                      <p
                        className="text-[11px]"
                        style={{ color: "var(--on-surface-dim)" }}
                      >
                        {sub.agentName || sub.assignedAgentId}
                      </p>
                    </div>
                    <StatusBadge status={sub.status} />
                  </Link>
                ))}
              </div>
            </div>
          )}

          {/* Parent Task Link */}
          {task.parentTaskId && (
            <Link
              href={`/tasks/${task.parentTaskId}`}
              className="flex items-center gap-3 p-4 rounded-xl transition-colors hover:bg-surface-high"
              style={{ background: "var(--surface-container)" }}
            >
              <ArrowLeft
                className="w-4 h-4"
                style={{ color: "var(--on-surface-dim)" }}
              />
              <span className="text-sm">View Parent Task</span>
            </Link>
          )}
        </div>
      </div>
    </>
  );
}

function InfoRow({
  label,
  value,
}: {
  label: string;
  value: React.ReactNode;
}) {
  return (
    <div className="flex items-center justify-between">
      <span
        className="text-[11px] uppercase tracking-[0.05rem]"
        style={{ color: "var(--on-surface-dim)" }}
      >
        {label}
      </span>
      {value}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { ListTodo, Play, Loader2 } from "lucide-react";
import { api } from "@/lib/api";
import type { Agent } from "@/lib/api";
import { PageHeader } from "@/components/page-header";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";

export default function CreateTaskPage() {
  const router = useRouter();
  const [agents, setAgents] = useState<Agent[]>([]);
  const [saving, setSaving] = useState(false);

  const [form, setForm] = useState({
    title: "",
    input: "",
    assignedAgentId: "",
    allowDelegation: true,
    requiresApproval: false,
  });

  useEffect(() => {
    api.agents
      .list(true)
      .then(setAgents)
      .catch(() => {});
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);

    try {
      const task = await api.tasks.create(form);
      // Auto-execute
      await api.tasks.execute(task.id);
      router.push(`/tasks/${task.id}`);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <PageHeader
        title="Create Task"
        description="Assign a task to an agent for execution"
      />

      <form onSubmit={handleSubmit} className="max-w-6xl space-y-6 md:space-y-0 md:grid md:grid-cols-12 md:gap-8 w-full mb-10">
        {/* Left Column: Task Info & Input */}
        <div className="md:col-span-8 space-y-6">
          {/* Title */}
          <div className="space-y-3">
            <Label
              htmlFor="title"
              className="text-xs uppercase tracking-[0.05rem] font-bold"
              style={{ color: "var(--on-surface-dim)" }}
            >
              Task Title
            </Label>
            <Input
              id="title"
              value={form.title}
              onChange={(e) => setForm({ ...form, title: e.target.value })}
              placeholder="e.g., Research latest AI trends"
              required
              className="bg-surface-container border-0 text-foreground h-12 text-base px-4"
            />
          </div>

          {/* Input */}
          <div className="space-y-3 pt-2">
            <Label
              htmlFor="input"
              className="text-xs uppercase tracking-[0.05rem] font-bold"
              style={{ color: "var(--on-surface-dim)" }}
            >
              Task Input / Instructions
            </Label>
            <Textarea
              id="input"
              value={form.input}
              onChange={(e) => setForm({ ...form, input: e.target.value })}
              placeholder="Describe what the agent should do in detail..."
              rows={16}
              required
              className="bg-surface-lowest border-0 text-foreground font-mono text-sm resize-y p-5 rounded-xl shadow-sm leading-relaxed min-h-[300px]"
